func (o *DeprecatedAPI) Preload(name string, retrieved any) error {
	if o == nil {
		return nil
	}

	switch name {
	case "Cluster":
		rel, ok := retrieved.(*Cluster)
		if !ok {
			return fmt.Errorf("deprecatedAPI cannot load %T as %q", retrieved, name)
		}

		o.R.Cluster = rel

		if rel != nil {
			rel.R.DeprecatedApis = DeprecatedAPISlice{o}
		}
		return nil
	case "Organization":
		rel, ok := retrieved.(*Organization)
		if !ok {
			return fmt.Errorf("deprecatedAPI cannot load %T as %q", retrieved, name)
		}

		o.R.Organization = rel

		if rel != nil {
			rel.R.DeprecatedApis = DeprecatedAPISlice{o}
		}
		return nil
	default:
		return fmt.Errorf("deprecatedAPI has no relationship %q", name)
	}
}

