// LoadCluster loads the deprecatedAPI's Cluster into the .R struct
func (o *DeprecatedAPI) LoadCluster(ctx context.Context, exec bob.Executor, mods ...bob.Mod[*dialect.SelectQuery]) error {
	if o == nil {
		return nil
	}

	// Reset the relationship
	o.R.Cluster = nil

	related, err := o.Cluster(mods...).One(ctx, exec)
	if err != nil {
		return err
	}

	related.R.DeprecatedApis = DeprecatedAPISlice{o}

	o.R.Cluster = related
	return nil
}

// LoadCluster loads the deprecatedAPI's Cluster into the .R struct
func (os DeprecatedAPISlice) LoadCluster(ctx context.Context, exec bob.Executor, mods ...bob.Mod[*dialect.SelectQuery]) error {
	if len(os) == 0 {
		return nil
	}

	clusters, err := os.Cluster(mods...).All(ctx, exec)
	if err != nil {
		return err
	}

	for _, o := range os {
		if o == nil {
			continue
		}

		for _, rel := range clusters {

			if !(o.ClusterID == rel.ID) {
				continue
			}

			rel.R.DeprecatedApis = append(rel.R.DeprecatedApis, o)

			o.R.Cluster = rel
			break
		}
	}

	return nil
}

