type deprecatedAPIJoins[Q dialect.Joinable] struct {
	typ          string
	Cluster      modAs[Q, clusterColumns]
	Organization modAs[Q, organizationColumns]
}

func (j deprecatedAPIJoins[Q]) aliasedAs(alias string) deprecatedAPIJoins[Q] {
	return buildDeprecatedAPIJoins[Q](buildDeprecatedAPIColumns(alias), j.typ)
}

func buildDeprecatedAPIJoins[Q dialect.Joinable](cols deprecatedAPIColumns, typ string) deprecatedAPIJoins[Q] {
	return deprecatedAPIJoins[Q]{
		typ: typ,
		Cluster: modAs[Q, clusterColumns]{
			c: Clusters.Columns,
			f: func(to clusterColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, Clusters.Name().As(to.Alias())).On(
						to.ID.EQ(cols.ClusterID),
					))
				}

				return mods
			},
		},
		Organization: modAs[Q, organizationColumns]{
			c: Organizations.Columns,
			f: func(to organizationColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, Organizations.Name().As(to.Alias())).On(
						to.ID.EQ(cols.OrganizationID),
					))
				}

				return mods
			},
		},
	}
}
